		path.addLine(to: CGPoint(x: frame.minX + 0.58843 * frame.width, y: frame.minY + 0.77823 * frame.height))
		path.addLine(to: CGPoint(x: frame.minX + 0.52973 * frame.width, y: frame.minY + 0.72275 * frame.height))
		path.addLine(to: CGPoint(x: frame.minX + 0.47103 * frame.width, y: frame.minY + 0.77823 * frame.height))
		path.addLine(to: CGPoint(x: frame.minX + 0.52973 * frame.width, y: frame.minY + 0.83371 * frame.height))
		path.closeSubpath()
		
			//// Rectangle 97 Drawing
		path.move(to: CGPoint(x: frame.minX + 0.29496 * frame.width, y: frame.minY + 0.83369 * frame.height))
		path.addLine(to: CGPoint(x: frame.minX + 0.47105 * frame.width, y: frame.minY + 1.00015 * frame.height))
		path.addLine(to: CGPoint(x: frame.minX + 0.52975 * frame.width, y: frame.minY + 0.94466 * frame.height))
		path.addLine(to: CGPoint(x: frame.minX + 0.35366 * frame.width, y: frame.minY + 0.77821 * frame.height))
		path.addLine(to: CGPoint(x: frame.minX + 0.29496 * frame.width, y: frame.minY + 0.83369 * frame.height))
		path.closeSubpath()
		
		return path
	}
}

